create extension if not exists pgcrypto;
create type public.quote_status as enum ('Draft','Sent','Pending','Won','Lost');
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade, user_id uuid generated always as (id) stored, email text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.user_settings (id uuid primary key default gen_random_uuid(), user_id uuid not null unique references auth.users(id) on delete cascade, business_name text not null default '', user_name text not null default '', telephone text not null default '', google_review_link text not null default '', follow_up_message text not null default 'Hi [customer name], I hope you’re well. I’m following up regarding the quotation for [job description]. Please let me know if you have any questions or would like to arrange a suitable start date. Kind regards.', review_request_message text not null default 'Hi [customer name], thank you for choosing us for your recent work. We’d really appreciate it if you could leave a short Google review about your experience: [review link]', follow_up_schedule integer[] not null default '{3,7,14,30}', created_at timestamptz not null default now(), updated_at timestamptz not null default now(), constraint schedule_positive check (array_length(follow_up_schedule,1)>0 and 0 < all(follow_up_schedule)));
create table public.customers (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null check(length(trim(name))>=2), mobile text, email text, address text, notes text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.quotes (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, customer_id uuid not null references public.customers(id) on delete restrict, job_description text not null check(length(trim(job_description))>=3), value_pence bigint not null check(value_pence>0), quote_date date not null, status public.quote_status not null default 'Draft', next_follow_up_date date, notes text, completed_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), constraint completion_only_when_won check(completed_at is null or status='Won'));
create table public.follow_up_history (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, quote_id uuid not null references public.quotes(id) on delete cascade, action text not null check(action in ('completed','snooze')), notes text, created_at timestamptz not null default now());
create index customers_user_name_idx on public.customers(user_id,name);create index quotes_user_status_idx on public.quotes(user_id,status);create index quotes_user_followup_idx on public.quotes(user_id,next_follow_up_date);create index history_user_quote_idx on public.follow_up_history(user_id,quote_id);
create or replace function public.set_updated_at() returns trigger language plpgsql security invoker set search_path='' as $$begin new.updated_at=now();return new;end$$;
create trigger customers_updated before update on public.customers for each row execute function public.set_updated_at();create trigger quotes_updated before update on public.quotes for each row execute function public.set_updated_at();create trigger settings_updated before update on public.user_settings for each row execute function public.set_updated_at();create trigger profiles_updated before update on public.profiles for each row execute function public.set_updated_at();
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path='' as $$begin insert into public.profiles(id,email) values(new.id,new.email);insert into public.user_settings(user_id,user_name) values(new.id,coalesce(new.raw_user_meta_data->>'name',''));return new;end$$;
create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
alter table public.profiles enable row level security;alter table public.user_settings enable row level security;alter table public.customers enable row level security;alter table public.quotes enable row level security;alter table public.follow_up_history enable row level security;
create policy profiles_own_all on public.profiles for all to authenticated using(user_id=(select auth.uid())) with check(user_id=(select auth.uid()));create policy settings_own_all on public.user_settings for all to authenticated using(user_id=(select auth.uid())) with check(user_id=(select auth.uid()));create policy customers_own_all on public.customers for all to authenticated using(user_id=(select auth.uid())) with check(user_id=(select auth.uid()));create policy quotes_own_all on public.quotes for all to authenticated using(user_id=(select auth.uid())) with check(user_id=(select auth.uid()) and exists(select 1 from public.customers c where c.id=customer_id and c.user_id=(select auth.uid())));create policy history_own_all on public.follow_up_history for all to authenticated using(user_id=(select auth.uid())) with check(user_id=(select auth.uid()) and exists(select 1 from public.quotes q where q.id=quote_id and q.user_id=(select auth.uid())));
revoke all on all tables in schema public from anon;grant select,insert,update,delete on public.profiles,public.user_settings,public.customers,public.quotes,public.follow_up_history to authenticated;
